"""
Written By: Niladri Banerjee
Written Date: 21/05/2024
Purpose:			 
		change property visible to true and false of button up down and remove
		as per condition.			
"""	
selectedRow = self.props.selection.selectedRow
pydata = self.props.data
self.parent.getChild("cntUpDown").getChild("imgRemove").meta.visible=bool(1)
if(selectedRow!=0):
	self.parent.getChild("cntUpDown").getChild("imgUp").meta.visible=bool(1)
else:
	self.parent.getChild("cntUpDown").getChild("imgUp").meta.visible=0

if(selectedRow!= (len(pydata)-1)):
	self.parent.getChild("cntUpDown").getChild("imgDown").meta.visible=1
else:
	self.parent.getChild("cntUpDown").getChild("imgDown").meta.visible=0

if(len(pydata) > 0):
	for rows in range(len(pydata)):
		if(selectedRow == rows):
			self.view.custom.seqNumber= pydata[rows]['Sequence']
